            int declEnd = afterDeclStart.indexOf("?>");
            if (declEnd != -1) {
                String afterDecl = afterDeclStart.substring(declEnd + 2).trim();
                // Keep the content before and after, removing the misplaced declaration
                return beforeDecl + afterDecl;
            }
        }

        // Find if there are multiple XML declarations
        int secondXmlDecl = trimmed.indexOf("<?xml", 5); // Start search after potential first declaration
        if (secondXmlDecl != -1) {
            // Remove the second XML declaration
            String beforeSecond = trimmed.substring(0, secondXmlDecl);
            String afterSecondStart = trimmed.substring(secondXmlDecl);
            int declEnd = afterSecondStart.indexOf("?>");
            if (declEnd != -1) {
                String afterSecond = afterSecondStart.substring(declEnd + 2);
                return beforeSecond + afterSecond;
            }
        }

        // If XML declaration is not at the very beginning but there's no content before it,
        // just trim leading whitespace
        if (firstXmlDeclStart > 0) {
            // Check if it's just whitespace before
            String beforeDecl = trimmed.substring(0, firstXmlDeclStart);
            if (beforeDecl.trim().isEmpty()) {
                return trimmed.substring(firstXmlDeclStart);
            }
        }

        return trimmed;
    }

    /**
     * Custom exception for configuration loading errors.
     */
    public static class ConfigurationLoadException extends RuntimeException {

        public ConfigurationLoadException(String message) {
            super(message);
        }

        public ConfigurationLoadException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
